const body = $input.first().json.body || $input.first().json;
const allowedPlatforms = ['instagram', 'twitter', 'linkedin', 'facebook'];
const platform = (body.platform || 'instagram').toLowerCase();

if (!body.filename && !body.fileUrl) {
  throw new Error('Missing required fields: provide filename or fileUrl');
}
if (!allowedPlatforms.includes(platform)) {
  throw new Error(`Invalid platform. Must be one of: ${allowedPlatforms.join(', ')}`);
}

const charLimits = { twitter: 280, instagram: 2200, linkedin: 3000, facebook: 63206 };
const filename = body.filename || body.fileUrl?.split('/').pop() || 'asset';
const ext = filename.split('.').pop()?.toLowerCase();
const isVideo = ['mp4', 'mov', 'avi', 'webm'].includes(ext);
const isImage = ['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext);
const cleanName = filename
  .replace(/\.[^.]+$/, '')
  .replace(/[-_]/g, ' ')
  .replace(/([a-z])([A-Z])/g, '$1 $2')
  .toLowerCase().trim();

return [{
  json: {
    filename,
    cleanName,
    fileUrl: body.fileUrl || null,
    platform,
    tone: body.tone || 'professional',
    includeHashtags: body.hashtags !== false,
    charLimit: charLimits[platform],
    contentType: isVideo ? 'video' : isImage ? 'image' : 'file',
    brand: body.brand || '',
    campaignContext: body.campaignContext || '',
    scheduleTime: body.scheduleTime || null,
    timestamp: new Date().toISOString()
  }
}];

const uploadResponse = $input.first().json;
const meta = $('Validate & Enrich Payload').first().json;

const cleanUrl =
  uploadResponse.url ||
  uploadResponse.link ||
  uploadResponse.data?.url ||
  uploadResponse.file?.url ||
  uploadResponse.shortUrl;

if (!cleanUrl) {
  throw new Error('Upload to URL did not return a valid public URL. Response: ' + JSON.stringify(uploadResponse));
}

return [{
  json: {
    ...meta,
    cleanUrl,
    uploadId: uploadResponse.id || uploadResponse.data?.id || null,
    fileSize: uploadResponse.size || uploadResponse.data?.size || null
  }
}];

